export declare const GRAMMAR_EXPRESSIONS = "\n(* ================================================================ *)\n(* 5. EXPRESSIONS \u2014 Precedence (lowest to highest)                  *)\n(*                                                                  *)\n(*  1. Assignment          =  +=  -=  *=  /=  %=  &=  |=  ^=       *)\n(*                          <<=  >>=                                *)\n(*  2. Ternary             ?  :                                     *)\n(*  3. Logical OR          ||                                       *)\n(*  4. Logical AND         &&                                       *)\n(*  5. Bitwise OR          |                                        *)\n(*  6. Bitwise NAND        ~&                                       *)\n(*  7. Bitwise XOR         ^                                        *)\n(*  8. Bitwise XNOR        ~^                                      *)\n(*  9. Bitwise AND         &                                        *)\n(* 10. Equality            ==  !=                                   *)\n(* 11. Relational          <  >  <=  >=                             *)\n(* 12. Shift               <<  >>                                   *)\n(* 13. Additive            +  -                                     *)\n(* 14. Multiplicative      *  /  %                                  *)\n(* 15. Unary prefix        !  ~  -  +  *  &  ++  --                 *)\n(* 16. Postfix             ()  []  .  ++  --                         *)\n(* 17. Primary             literals, identifiers, _, parens,        *)\n(*                          lambdas, casts                          *)\n(* ================================================================ *)\n\nExpression\n    = LambdaExpression\n    | AssignmentExpression\n    ;\n\n(* --- Lambda ---------------------------------------------------- *)\n(* Single-expression:  (int32 a, int32 b) -> a + b                 *)\n(* Block:              (int32 a) -> { return a + 1; }              *)\n(* Zero-arg:           () -> 42                                     *)\n\nLambdaExpression\n    = \"(\" [ ParameterList ] \")\" \"->\" LambdaBody\n    ;\n\nLambdaBody\n    = Block\n    | AssignmentExpression\n    ;\n\nParameterList\n    = Parameter { \",\" Parameter }\n    ;\n\nParameter\n    = Type \"...\" Identifier                                    (* varargs \u2014 must be last *)\n    | Type Identifier\n    ;\n\n(* --- Assignment (right-associative) ----------------------------- *)\n\nAssignmentExpression\n    = TernaryExpression [ AssignmentOperator AssignmentExpression ]\n    ;\n\nAssignmentOperator\n    = \"=\" | \"+=\" | \"-=\" | \"*=\" | \"/=\" | \"%=\"\n    | \"&=\" | \"|=\" | \"^=\" | \"<<=\" | \">>=\"\n    ;\n\n(* --- Ternary (right-associative) -------------------------------- *)\n\nTernaryExpression\n    = LogicalOrExpression [ \"?\" Expression \":\" TernaryExpression ]\n    ;\n\n(* --- Logical OR ------------------------------------------------- *)\n\nLogicalOrExpression\n    = LogicalAndExpression { \"||\" LogicalAndExpression }\n    ;\n\n(* --- Logical AND ------------------------------------------------ *)\n\nLogicalAndExpression\n    = BitwiseOrExpression { \"&&\" BitwiseOrExpression }\n    ;\n\n(* --- Bitwise OR ------------------------------------------------- *)\n\nBitwiseOrExpression\n    = BitwiseNandExpression { \"|\" BitwiseNandExpression }\n    ;\n\n(* --- Bitwise NAND ----------------------------------------------- *)\n\nBitwiseNandExpression\n    = BitwiseXorExpression { \"~&\" BitwiseXorExpression }\n    ;\n\n(* --- Bitwise XOR ------------------------------------------------ *)\n\nBitwiseXorExpression\n    = BitwiseXnorExpression { \"^\" BitwiseXnorExpression }\n    ;\n\n(* --- Bitwise XNOR ---------------------------------------------- *)\n\nBitwiseXnorExpression\n    = BitwiseAndExpression { \"~^\" BitwiseAndExpression }\n    ;\n\n(* --- Bitwise AND ------------------------------------------------ *)\n\nBitwiseAndExpression\n    = EqualityExpression { \"&\" EqualityExpression }\n    ;\n\n(* --- Equality --------------------------------------------------- *)\n\nEqualityExpression\n    = RelationalExpression { ( \"==\" | \"!=\" ) RelationalExpression }\n    ;\n\n(* --- Relational ------------------------------------------------- *)\n\nRelationalExpression\n    = ShiftExpression { ( \"<\" | \">\" | \"<=\" | \">=\" ) ShiftExpression }\n    ;\n\n(* --- Shift ------------------------------------------------------ *)\n\nShiftExpression\n    = AdditiveExpression { ( \"<<\" | \">>\" ) AdditiveExpression }\n    ;\n\n(* --- Additive --------------------------------------------------- *)\n\nAdditiveExpression\n    = MultiplicativeExpression { ( \"+\" | \"-\" ) MultiplicativeExpression }\n    ;\n\n(* --- Multiplicative --------------------------------------------- *)\n\nMultiplicativeExpression\n    = UnaryExpression { ( \"*\" | \"/\" | \"%\" ) UnaryExpression }\n    ;\n\n(* --- Unary prefix ----------------------------------------------- *)\n\nUnaryExpression\n    = ( \"!\" | \"~\" | \"-\" | \"+\" ) UnaryExpression\n    | \"++\" UnaryExpression                                     (* prefix increment *)\n    | \"--\" UnaryExpression                                     (* prefix decrement *)\n    | PostfixExpression\n    ;\n\n(* --- Postfix ---------------------------------------------------- *)\n(* Function call, array indexing, and member access.                 *)\n\nPostfixExpression\n    = PrimaryExpression { PostfixOp }\n    ;\n\nPostfixOp\n    = \"(\" [ ArgumentList ] \")\"       (* function call      *)\n    | \"[\" Expression \"]\"              (* array index        *)\n    | \".\" Identifier                  (* member access      *)\n    | \"++\"                            (* postfix increment  *)\n    | \"--\"                            (* postfix decrement  *)\n    ;\n\nArgumentList\n    = Expression { \",\" Expression }\n    ;\n\n";
